define("tool_guidance/condition_builder", [], function() { "use strict";

let root;
let facts;
let strings;
let factIndex;
let numberFacts;
let rowsRegion;
let hidden;
let preview;
let validity;
let uidSeq = 0;

const uid = () => `tgc_${uidSeq++}`;

const el = (tag, attrs = {}, kids = []) => {
    const n = document.createElement(tag);
    Object.entries(attrs).forEach(([k, v]) => {
        if (k === 'class') {
            n.className = v;
        } else if (k === 'text') {
            n.textContent = v;
        } else {
            n.setAttribute(k, v);
        }
    });
    kids.forEach((c) => n.appendChild(c));
    return n;
};

const factSelect = (selected) => {
    const s = el('select', {'class': 'form-select form-select-sm', 'data-role': 'fact'});
    facts.groups.forEach((g) => {
        if (!g.facts.length) {
            return;
        }
        const og = el('optgroup', {label: g.label});
        g.facts.forEach((f) => {
            const o = el('option', {value: f.key, text: f.label});
            if (f.key === selected) {
                o.selected = true;
            }
            og.appendChild(o);
        });
        s.appendChild(og);
    });
    return s;
};

const opSelect = (fact, selected) => {
    const s = el('select', {'class': 'form-select form-select-sm', 'data-role': 'op'});
    (fact ? fact.operators : []).forEach((op) => {
        const o = el('option', {value: op, text: strings.ops[op] || op});
        if (op === selected) {
            o.selected = true;
        }
        s.appendChild(o);
    });
    return s;
};

const valueWidget = (fact, op, clause) => {
    const wrap = el('div', {'data-region': 'value'});
    if (!fact) {
        return wrap;
    }
    if (op === 'in') {
        const chosen = Array.isArray(clause.value) ? clause.value : [];
        (fact.values || []).forEach((v) => {
            const cb = el('input', {'type': 'checkbox', 'value': v, 'data-role': 'setval', 'class': 'form-check-input me-1'});
            if (chosen.indexOf(v) !== -1) {
                cb.checked = true;
            }
            wrap.appendChild(el('label', {'class': 'me-2'}, [cb, document.createTextNode(v)]));
        });
        return wrap;
    }
    if (fact.type === 'bool') {
        const s = el('select', {'class': 'form-select form-select-sm', 'data-role': 'literal'});
        [['true', strings.yes], ['false', strings.no]].forEach(([val, txt]) => {
            const o = el('option', {value: val, text: txt});
            if (clause.value === val) {
                o.selected = true;
            }
            s.appendChild(o);
        });
        wrap.appendChild(s);
        return wrap;
    }
    if (fact.type === 'enum') {
        const s = el('select', {'class': 'form-select form-select-sm', 'data-role': 'literal'});
        (fact.values || []).forEach((v) => {
            const o = el('option', {value: v, text: v});
            if (clause.value === v) {
                o.selected = true;
            }
            s.appendChild(o);
        });
        wrap.appendChild(s);
        return wrap;
    }
    // Numeric: literal value or another number fact.
    const name = uid();
    const isFact = clause.operandkind === 'fact';
    const litRadio = el('input', {'type': 'radio', 'name': name, 'value': 'literal', 'class': 'form-check-input me-1', 'data-role': 'kind'});
    const factRadio = el('input', {'type': 'radio', 'name': name, 'value': 'fact', 'class': 'form-check-input me-1', 'data-role': 'kind'});
    litRadio.checked = !isFact;
    factRadio.checked = isFact;

    const num = el('input', {'type': 'number', 'class': 'form-control form-control-sm d-inline-block w-auto', 'data-role': 'litnum'});
    num.value = isFact ? '' : (clause.value ?? '');

    const factPick = el('select', {'class': 'form-select form-select-sm d-inline-block w-auto', 'data-role': 'factval'});
    numberFacts.forEach((f) => {
        const o = el('option', {value: f.key, text: f.label});
        if (isFact && clause.value === f.key) {
            o.selected = true;
        }
        factPick.appendChild(o);
    });

    const litLabel = el('label', {'class': 'me-3'}, [litRadio, document.createTextNode(strings.literal + ' '), num]);
    const factLabel = el('label', {}, [factRadio, document.createTextNode(strings.fact + ' '), factPick]);
    wrap.append(litLabel, factLabel);

    const toggle = () => {
        num.disabled = !litRadio.checked;
        factPick.disabled = !factRadio.checked;
    };
    litRadio.addEventListener('change', () => {
        toggle();
        sync();
    });
    factRadio.addEventListener('change', () => {
        toggle();
        sync();
    });
    toggle();
    return wrap;
};

const addRow = (clause) => {
    const row = el('div', {'class': 'tool-guidance-condition-row d-flex flex-wrap align-items-center gap-2 mb-2'});
    const factCell = el('div', {}, [factSelect(clause.fact)]);
    const opCell = el('div', {'data-region': 'opcell'});
    const valCell = el('div', {'data-region': 'valcell', 'class': 'flex-grow-1'});
    const rm = el('button', {'type': 'button', 'class': 'btn btn-icon btn-link text-danger p-1', 'data-action': 'remove', 'aria-label': strings.remove});
    rm.textContent = '×';

    const fs = factCell.querySelector('[data-role="fact"]');
    const renderOp = () => {
        opCell.innerHTML = '';
        opCell.appendChild(opSelect(factIndex[fs.value], clause.op));
    };
    const renderVal = () => {
        const op = opCell.querySelector('[data-role="op"]');
        valCell.innerHTML = '';
        valCell.appendChild(valueWidget(factIndex[fs.value], op ? op.value : '', clause));
    };

    renderOp();
    renderVal();

    fs.addEventListener('change', () => {
        clause.op = undefined;
        clause.value = undefined;
        clause.operandkind = undefined;
        renderOp();
        renderVal();
        sync();
    });
    opCell.addEventListener('change', () => {
        clause.value = undefined;
        clause.operandkind = undefined;
        renderVal();
        sync();
    });
    valCell.addEventListener('change', sync);
    valCell.addEventListener('input', sync);
    rm.addEventListener('click', () => {
        row.remove();
        sync();
    });

    row.append(factCell, opCell, valCell, rm);
    rowsRegion.appendChild(row);
};

const readRow = (row) => {
    const fact = row.querySelector('[data-role="fact"]').value;
    const opEl = row.querySelector('[data-role="op"]');
    const op = opEl ? opEl.value : '';
    const clause = {fact, op};
    if (op === 'in') {
        clause.operandkind = 'set';
        clause.value = Array.from(row.querySelectorAll('[data-role="setval"]:checked')).map((c) => c.value);
        return clause;
    }
    const factEl = factIndex[fact];
    if (factEl && (factEl.type === 'int' || factEl.type === 'float')) {
        const kindEl = row.querySelector('[data-role="kind"]:checked');
        if (kindEl && kindEl.value === 'fact') {
            clause.operandkind = 'fact';
            clause.value = row.querySelector('[data-role="factval"]').value;
        } else {
            clause.operandkind = 'literal';
            clause.value = row.querySelector('[data-role="litnum"]').value;
        }
        return clause;
    }
    clause.operandkind = 'literal';
    const lit = row.querySelector('[data-role="literal"]');
    clause.value = lit ? lit.value : '';
    return clause;
};

const naiveCompile = (clauses) => clauses.filter((c) => c.fact && c.op).map((c) => {
    if (c.operandkind === 'set') {
        return `${c.fact} ${c.op} (${(c.value || []).join('|')})`;
    }
    return `${c.fact} ${c.op} ${c.value ?? ''}`;
}).join(' AND ');

const isComplete = (clauses) => clauses.length === 0 || clauses.every((c) => {
    if (!c.fact || !c.op) {
        return false;
    }
    return c.operandkind === 'set' ? (c.value || []).length > 0 : String(c.value ?? '').trim() !== '';
});

const sync = () => {
    const clauses = Array.from(rowsRegion.querySelectorAll('.tool-guidance-condition-row')).map(readRow);
    hidden.value = JSON.stringify(clauses);
    const dsl = naiveCompile(clauses);
    preview.textContent = dsl;
    if (isComplete(clauses)) {
        validity.textContent = clauses.length ? '✓' : strings.matchesall;
        validity.className = 'tool-guidance-condition-validity text-success';
    } else {
        validity.textContent = '⚠ ' + strings.incomplete;
        validity.className = 'tool-guidance-condition-validity text-warning';
    }
};

const init = (id) => {
    root = document.getElementById(id);
    if (!root) {
        return;
    }
    facts = JSON.parse(root.dataset.facts);
    strings = JSON.parse(root.dataset.strings);
    factIndex = {};
    numberFacts = [];
    facts.groups.forEach((g) => g.facts.forEach((f) => {
        factIndex[f.key] = f;
        if (f.type === 'int' || f.type === 'float') {
            numberFacts.push(f);
        }
    }));
    rowsRegion = root.querySelector('[data-region="rows"]');
    preview = root.querySelector('[data-region="preview"]');
    validity = root.querySelector('[data-region="validity"]');
    hidden = root.closest('form').querySelector('input[name="conditionclauses"]');

    root.querySelector('[data-action="add"]').addEventListener('click', () => {
        addRow({});
        sync();
    });

    let clauses = [];
    try {
        clauses = JSON.parse(hidden.value || '[]');
    } catch (e) {
        clauses = [];
    }
    if (!clauses.length) {
        clauses = [{}];
    }
    clauses.forEach(addRow);
    sync();
};

return {init: init};
});
